/// End-to-end golden test: deposit→transfer using the actual compiled Circom
/// circuit. Proves that the real transfer.circom soundness relation (B >= A,
/// no overdraft, commitment openings) integrates correctly with the on-chain
/// Piilo contract logic. If contract and circuit disagree on G, H, or
/// commitment arithmetic, the proof verification fails here.
#[test]
fn real_circom_transfer_proof_is_accepted() {
    let env = Env::default();
    env.cost_estimate().disable_resource_limits();
    env.cost_estimate().budget().reset_unlimited();
    env.mock_all_auths();

    let admin = Address::generate(&env);
    let sac = env.register_stellar_asset_contract_v2(admin.clone());
    let token_id = sac.address();
    let verifier_id = env.register(verifier_contract::WASM, ());

    let mut r = rng();
    let withdraw_vk_placeholder = vk_to_sdk(&env, &setup_circuit::<3>(&mut r).pk.vk);

    let piilo_id = env.register(
        Piilo,
        (circuit_g(&env), circuit_h(&env), verifier_id,
         real_transfer_vk(&env), withdraw_vk_placeholder, token_id.clone()),
    );
    let client = PiiloClient::new(&env, &piilo_id);

    let alice = Address::generate(&env);
    let bob = Address::generate(&env);
    fund(&env, &token_id, &alice, 1_000);

    // deposit(500, r_B=111): contract computes C_B = commit(500, 111, G, H).
    // If this matches c_b_point() from the circuit, the proof below passes.
    client.deposit(&alice, &500, &blinding(&env, 111));

    let deposited_c_b = client.get_account(&alice).unwrap().balance_commitment;
    assert_eq!(deposited_c_b, c_b_point(&env), "contract commit() disagrees with circuit on C_B");

    let c_a = c_a_point(&env);
    let c_new = c_new_point(&env);
    let proof = real_transfer_proof(&env);
    let note = Bytes::from_array(&env, &[0u8; 4]);

    client.transfer(&alice, &bob, &c_a, &c_new, &proof, &note);

    let alice_account = client.get_account(&alice).unwrap();
    assert_eq!(alice_account.balance_commitment, c_new);
    assert_eq!(alice_account.nonce, 1);

    let bob_account = client.get_account(&bob).unwrap();
    assert!(bob_account.has_pending);
    assert_eq!(bob_account.pending_commitment, c_a);
}

/// End-to-end golden test: deposit→withdraw using the actual compiled Circom
/// circuit. Validates that withdraw.circom (proves knowledge of r_B s.t.
/// C_B opens to B) integrates correctly.
#[test]
fn real_circom_withdraw_proof_is_accepted() {
    let env = Env::default();
    env.cost_estimate().disable_resource_limits();
    env.cost_estimate().budget().reset_unlimited();
    env.mock_all_auths();

    let admin = Address::generate(&env);
    let sac = env.register_stellar_asset_contract_v2(admin.clone());
    let token_id = sac.address();
    let verifier_id = env.register(verifier_contract::WASM, ());

    let mut r = rng();
    let transfer_vk_placeholder = vk_to_sdk(&env, &setup_circuit::<6>(&mut r).pk.vk);

    let piilo_id = env.register(
        Piilo,
        (circuit_g(&env), circuit_h(&env), verifier_id,
         transfer_vk_placeholder, real_withdraw_vk(&env), token_id.clone()),
    );
    let client = PiiloClient::new(&env, &piilo_id);
    let token_client = token::Client::new(&env, &token_id);

    let alice = Address::generate(&env);
    fund(&env, &token_id, &alice, 1_000);

    client.deposit(&alice, &500, &blinding(&env, 111));

    let deposited_c_b = client.get_account(&alice).unwrap().balance_commitment;
    assert_eq!(deposited_c_b, c_b_point(&env), "contract commit() disagrees with circuit on C_B");

    let proof = real_withdraw_proof(&env);
    client.withdraw(&alice, &500, &proof);

    assert_eq!(token_client.balance(&alice), 1_000);
    assert_eq!(client.get_vault_balance(), 0);

    let account = client.get_account(&alice).unwrap();
    assert_eq!(account.balance_commitment, commitment::identity(&env));
}
